    "slug": "petty-cash-reporting-standards",
    "date": "2026-06-24",
    "readTime": 3,
    "image": "https://images.pexels.com/photos/4386531/pexels-photo-4386531.jpeg?auto=compress&cs=tinysrgb&w=800",
